INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) VALUES
('single_choice', '一物体从静止开始做匀加速直线运动，加速度为2m/s2，则3s末的速度为( )', '[{"key":"A","text":"3 m/s"},{"key":"B","text":"5 m/s"},{"key":"C","text":"6 m/s"},{"key":"D","text":"9 m/s"}]', '["C"]', 'v=at=2*3=6 m/s，初速度为0时直接用v=at', 'easy', 11, NOW()),
('single_choice', '一物体做自由落体运动，下落2s内的位移为( )(g=10m/s2)', '[{"key":"A","text":"10m"},{"key":"B","text":"20m"},{"key":"C","text":"30m"},{"key":"D","text":"40m"}]', '["B"]', '自由落体位移h=1/2gt2=0.5*10*4=20m', 'easy', 11, NOW()),
('single_choice', '质量为2kg的物体在光滑水平面上受到10N的恒力作用，加速度大小为( )', '[{"key":"A","text":"2 m/s2"},{"key":"B","text":"5 m/s2"},{"key":"C","text":"10 m/s2"},{"key":"D","text":"20 m/s2"}]', '["B"]', 'F=ma，a=F/m=10/2=5 m/s2', 'easy', 12, NOW()),
('true_false', '作用力与反作用力大小相等、方向相反、作用在同一物体上。( )', '[{"key":"A","text":"正确"},{"key":"B","text":"错误"}]', '["B"]', '牛顿第三定律：作用力与反作用力作用在不同物体上', 'easy', 12, NOW()),
('single_choice', '质量为1kg的物体从10m高处自由下落，落地时动能为( )(g=10m/s2)', '[{"key":"A","text":"50J"},{"key":"B","text":"100J"},{"key":"C","text":"150J"},{"key":"D","text":"200J"}]', '["B"]', '机械能守恒，mgh=1*10*10=100J全部转化为动能', 'medium', 15, NOW()),
('fill_blank', '弹簧振子做简谐运动，在平衡位置时动能最___，在最大位移处势能最___。', '[]', '["大","大"]', '平衡位置速度最大动能最大，最大位移处弹簧形变最大势能最大', 'medium', 15, NOW()),
('single_choice', '两个点电荷之间的静电力遵循( )', '[{"key":"A","text":"万有引力定律"},{"key":"B","text":"库仑定律"},{"key":"C","text":"欧姆定律"},{"key":"D","text":"楞次定律"}]', '["B"]', '库仑定律描述两点电荷间的静电力', 'easy', 16, NOW()),
('single_choice', 'She ___ to school by bus every day.', '[{"key":"A","text":"go"},{"key":"B","text":"goes"},{"key":"C","text":"going"},{"key":"D","text":"gone"}]', '["B"]', '一般现在时第三人称单数，动词加-s/-es。every day提示习惯性动作。', 'easy', 21, NOW()),
('single_choice', 'The book ___ on the desk is mine.', '[{"key":"A","text":"lay"},{"key":"B","text":"lying"},{"key":"C","text":"lied"},{"key":"D","text":"lies"}]', '["B"]', '现在分词短语作后置定语，lying on the desk修饰the book', 'medium', 21, NOW()),
('single_choice', 'I ___ my homework when you called me yesterday.', '[{"key":"A","text":"do"},{"key":"B","text":"was doing"},{"key":"C","text":"did"},{"key":"D","text":"have done"}]', '["B"]', '过去进行时：when引导的时间状语从句用一般过去时，主句用过去进行时', 'medium', 28, NOW()),
('true_false', '被动语态的基本结构是be+过去分词。( )', '[{"key":"A","text":"正确"},{"key":"B","text":"错误"}]', '["A"]', '被动语态基本结构确实是be+过去分词，时态由be动词体现', 'easy', 28, NOW()),
('single_choice', 'This is the school ___ I studied three years ago.', '[{"key":"A","text":"which"},{"key":"B","text":"that"},{"key":"C","text":"where"},{"key":"D","text":"when"}]', '["C"]', '先行词school在从句中作地点状语，用关系副词where', 'medium', 29, NOW()),
('single_choice', 'If I ___ you, I would study harder.', '[{"key":"A","text":"am"},{"key":"B","text":"was"},{"key":"C","text":"were"},{"key":"D","text":"be"}]', '["C"]', '与现在事实相反的虚拟语气，if从句用were', 'medium', 29, NOW()),
('single_choice', '___ is believed to be good for health.', '[{"key":"A","text":"Swim"},{"key":"B","text":"Swimming"},{"key":"C","text":"Swam"},{"key":"D","text":"Swum"}]', '["B"]', '动名词作主语，Swimming is believed to...', 'medium', 30, NOW()),
('single_choice', 'The Great Wall is one of the greatest ___ (wonder) in the world.', '[{"key":"A","text":"wonder"},{"key":"B","text":"wonders"},{"key":"C","text":"wondering"},{"key":"D","text":"wondered"}]', '["B"]', 'one of+复数名词，wonder的复数为wonders', 'easy', 27, NOW());
